def classify_primes(numbers):
    result = []
    for n in numbers:
        if n < 2:
            result.append(False)
        else:
            is_prime = True
            for i in range(2, int(n**0.5) + 1):
                if n % i == 0:
                    is_prime = False
                    break
            result.append(is_prime)
    return result

unit_tests:
import unittest

class TestClassifyPrimes(unittest.TestCase):
    def test_mixed_small(self):
        self.assertEqual(classify_primes([2, 3, 4, 5, 6]), [True, True, False, True, False])

    def test_all_primes(self):
        self.assertEqual(classify_primes([7, 11, 13]), [True, True, True])

    def test_no_primes(self):
        self.assertEqual(classify_primes([1, 0, 4, 9]), [False, False, False, False])

    def test_hidden_empty_list(self):
        self.assertEqual(classify_primes([]), [])

    def test_hidden_single_prime(self):
        self.assertEqual(classify_primes([2]), [True])

    def test_hidden_single_non_prime(self):
        self.assertEqual(classify_primes([1]), [False])

    def test_hidden_larger_numbers(self):
        self.assertEqual(classify_primes([97, 99, 100]), [True, False, False])

    def test_hidden_consecutive_range(self):
        self.assertEqual(classify_primes([17, 18, 19, 20, 21, 22, 23]), [True, False, True, False, False, False, True])

if __name__ == '__main__':
    unittest.main()
